/// <summary>
/// extension class for form ITMTable datasource ITMLine
/// </summary>
[ExtensionOf(formDataSourceStr(ITMTable, ITMLine))]
final class ETGITMTable_ITMLineDS_Extension
{
}

Method.Source:
/// <summary>
/// update design for inbound orders
/// </summary>
/// <returns>int</returns>
public int active()
{
    int ret = next active();

    this.updateDesignInbound();

    return ret;
}

/// <summary>
/// update design for inbound orders
/// </summary>
public void updateDesignInbound()
{
    FormDataSource      formDS          = this;
    ITMLine             itmLine         = formDS.cursor();
    ITMTable            itmTable;

    select firstonly RecId, ETGLandedCostType from itmTable where itmTable.ShipId == itmLine.ShipId;

    if(itmTable.RecId && itmTable.ETGLandedCostType == ETGLandedCostType::Inbound)
    {
        formDS.object(fieldNum(ITMLine, ETGOUTTransType)).visible(false);
        formDS.object(fieldNum(ITMLine, ETGGateInDate)).visible(false);
    }
}
